import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface SprintInfo {
  sprintName: string;
  totalStoryPoints: number;
  completedStoryPoints: number;
  remainingStoryPoints: number;
}

interface BurndownPoint {
  day: string;
  remainingPoints: number;
}

interface WidgetData {
  sprintInfo: SprintInfo;
  burndownChart: BurndownPoint[];
  storyPointsCompleted: number[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { sprintInfo, burndownChart } = widgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#212121', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FFC107' }}>
            {sprintInfo.sprintName}
          </Typography>
          <Stack direction="row" justifyContent="space-between">
            <Box>
              <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
                Total Points
              </Typography>
              <Typography variant="h5" fontWeight={700} sx={{ color: '#0D47A1' }}>
                {sprintInfo.totalStoryPoints}
              </Typography>
            </Box>
            <Box>
              <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
                Completed
              </Typography>
              <Typography variant="h5" fontWeight={700} sx={{ color: '#0D47A1' }}>
                {sprintInfo.completedStoryPoints}
              </Typography>
            </Box>
            <Box>
              <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
                Remaining
              </Typography>
              <Typography variant="h5" fontWeight={700} sx={{ color: '#FFC107' }}>
                {sprintInfo.remainingStoryPoints}
              </Typography>
            </Box>
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <LineChart
              series={[
                {
                  data: burndownChart.map(point => point.remainingPoints),
                  color: '#2196F3',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: burndownChart.map(point => point.day),
                  scaleType: 'band',
                  tickLabelStyle: { fontSize: 11, fill: '#BDBDBD' },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
